const chatId = $('When Executed by Another Workflow').first().json.chat_id;
const items = $input.all().map(item => item.json);
if (!items || items.length === 0 || Object.keys(items[0]).length === 0) {
  return [{ json: { message: '📭 No schedule data available.', chat_id: chatId } }];
}

// Extract unique time slots and courts
const timeslots = [...new Set(items.map(x => x.time_slot))].sort();
const courts = [...new Set(items.map(x => x.court_number))].sort();

// Get the date from first item - fix UTC timezone shift
let scheduleDate = 'Unknown date';
if (items[0]?.date) {
  const d = new Date(items[0].date);
  scheduleDate = d.toLocaleDateString('sv-SE', { timeZone: 'Europe/Warsaw' });
}

// Build header
let message = `<b>🏸 Court Schedule</b>\n`;
message += `<b>📅 ${scheduleDate}</b>\n\n`;

// Build monospace table header
message += '<pre>';
message += '🕓     ';
courts.forEach(court => {
  const courtNum = court.replace('Badminton ', '#');
  message += `${courtNum} `;
});
message += '\n';
message += '───────' + '────'.repeat(courts.length) + '\n';

const available_times = Object.entries(
  $input.all().map(i => i.json)
    .filter(slot => slot.is_available) // ← Filter first
    .reduce((acc, slot) => {
      const time = slot.time_slot.slice(0, 5);
      const court = slot.court_number.replace('Badminton ', '');
      acc[time] = acc[time] || [];
      acc[time].push(court);
      return acc;
    }, {})
).map(([time_slot, courts]) => ({ time_slot, courts }));

// Build table rows
timeslots.forEach(ts => {
  let timeDisplay = ts;
  if (ts.includes('T')) {
    timeDisplay = ts.substring(11, 16);
  } else if (ts.length > 5) {
    timeDisplay = ts.substring(0, 5);
  }
  message += timeDisplay + '  ';

  courts.forEach(court => {
    const slot = items.find(item => 
      item.time_slot === ts && item.court_number === court
    );

    if (!slot) {
      message += '⬜ ';
    } else if (slot.bot_user_id) {
      message += '🏸 ';  // booked by a bot user (takes priority — handles pre-sync window)
    } else if (slot.is_available) {
      message += '✅ ';
    } else {
      message += '❌ ';  // booked externally
    }
  });
  message += '\n';
});

message += '</pre>';
message += '\n✅ Available  🏸 Bot booking  ❌ External';

return [{ json: { message: message, chat_id: chatId, available_times: available_times } }];

